import { Link } from 'react-router-dom';
import logo from '../assets/logo.png';

export default function Footer() {
  return (
    <footer style={{
      background: '#f7f7f7',
      borderTop: '1px solid #e8e8e8',
      padding: '3rem 2rem 1.5rem',
      marginTop: '4rem',
    }}>
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
        gap: '2rem',
        maxWidth: '1100px',
        margin: '0 auto',
      }}>
        {/* Logo + Copyright */}
        <div>
          <img src={logo} alt="TurfX" style={{ height: '80px', objectFit: 'contain', marginBottom: '1rem' }} />
          <p style={{ color: '#888', fontSize: '0.85rem', lineHeight: 1.6 }}>
            © 2024 MetaQode Technologies Pvt. Ltd.<br />All Rights Reserved.
          </p>
        </div>

        {/* Company */}
        <div>
          <h4 style={{ color: '#888', fontSize: '0.8rem', fontWeight: '700', letterSpacing: '1px', marginBottom: '1.2rem', textTransform: 'uppercase' }}>
            Company
          </h4>
          {['About Us', 'Blogs', 'Contact', 'Careers', 'Partner With Us'].map(item => (
            <div key={item} style={{ marginBottom: '12px' }}>
              <Link to="/" style={{ color: '#444', textDecoration: 'none', fontSize: '0.9rem', fontWeight: '600', letterSpacing: '0.5px' }}>
                {item.toUpperCase()}
              </Link>
            </div>
          ))}
        </div>

        {/* Social */}
        <div>
          <h4 style={{ color: '#888', fontSize: '0.8rem', fontWeight: '700', letterSpacing: '1px', marginBottom: '1.2rem', textTransform: 'uppercase' }}>
            Social
          </h4>
          {['Instagram', 'Facebook', 'LinkedIn', 'Twitter'].map(item => (
            <div key={item} style={{ marginBottom: '12px' }}>
              <Link to="/" style={{ color: '#444', textDecoration: 'none', fontSize: '0.9rem', fontWeight: '600', letterSpacing: '0.5px' }}>
                {item.toUpperCase()}
              </Link>
            </div>
          ))}
        </div>

        {/* Privacy & Terms */}
        <div>
          <h4 style={{ color: '#888', fontSize: '0.8rem', fontWeight: '700', letterSpacing: '1px', marginBottom: '1.2rem', textTransform: 'uppercase' }}>
            Privacy & Terms
          </h4>
          {['FAQs', 'Privacy Policy', 'Terms of Service', 'Cancellation Policy'].map(item => (
            <div key={item} style={{ marginBottom: '12px' }}>
              <Link to="/" style={{ color: '#444', textDecoration: 'none', fontSize: '0.9rem', fontWeight: '600', letterSpacing: '0.5px' }}>
                {item.toUpperCase()}
              </Link>
            </div>
          ))}
        </div>
      </div>
    </footer>
  );
}
